quickstart_example:
GET /api/1/companies HTTP/1.1
Host: api.freee.co.jp
Authorization: Bearer {access_token}
Accept: application/json

Response: {"companies":[{"id":123,"display_name":"テスト株式会社","role":"admin"}]}

GET /v1/employees HTTP/1.1
Host: api.smarthr.jp
Authorization: Bearer {access_token}
Accept: application/json

Response: {"data":[{"id":"abc123","last_name":"田中","first_name":"太郎","email":"tanaka@example.com"}],"next_cursor":"xyz789"}

POST /v2/rooms/123456/messages HTTP/1.1
Host: api.chatwork.com
X-ChatWorkToken: {your_token}
Content-Type: application/x-www-form-urlencoded

body=Hello+from+agent!

Response: {"message_id":"789"}

GET /k/v1/records.json?app=1&query=status%3D%22Open%22 HTTP/1.1
Host: example.cybozu.com
X-Cybozu-API-Token: {api_token}

Response: {"records":[{"$id":{"value":"1"},"title":{"value":"タスクA"}}],"totalCount":"42"}

POST /api/chat.postMessage HTTP/1.1
Host: slack.com
Authorization: Bearer xoxb-your-token
Content-Type: application/json

{"channel":"C01234567","text":"Hello from agent!"}

Response: {"ok":true,"channel":"C01234567","ts":"1234567890.123456"}

GET /admin/api/2024-10/products.json?limit=5 HTTP/1.1
Host: mystore.myshopify.com
X-Shopify-Access-Token: {access_token}

Response: {"products":[{"id":123,"title":"商品A","variants":[{"price":"1500.00"}]}]}

GET /api/v3/offices HTTP/1.1
Host: accounting.moneyforward.com
Authorization: Bearer {access_token}

Response: {"offices":[{"id":123,"display_name":"テスト事務所"}]}

GET /v1/documents?status=waiting HTTP/1.1
Host: api.cloudsign.jp
X-Api-Key: {api_key}
X-Client-Id: {client_id}

Response: {"documents":[{"id":"doc_123","title":"業務委託契約書","status":"waiting"}]}

GET /v8/bizcards?name=田中&limit=10 HTTP/1.1
Host: api.sansan.com
Authorization: Bearer {access_token}

Response: {"data":[{"id":"bc_123","personName":{"lastName":"田中","firstName":"太郎"},"companyName":"株式会社テスト","email":"tanaka@test.co.jp"}]}

POST /v2/bot/message/push HTTP/1.1
Host: api.line.me
Authorization: Bearer {channel_access_token}
Content-Type: application/json

{"to":"U1234567890abcdef","messages":[{"type":"text","text":"Hello!"}]}

Response: {}  (200 OK, empty body on success)

GET /crm/v3/objects/contacts?limit=10&properties=email,firstname,lastname HTTP/1.1
Host: api.hubapi.com
Authorization: Bearer {token}

Response: {"results":[{"id":"123","properties":{"email":"tanaka@example.com","firstname":"太郎","lastname":"田中"}}]}

POST /v1/databases/{database_id}/query HTTP/1.1
Host: api.notion.com
Authorization: Bearer {token}
Notion-Version: 2022-06-28
Content-Type: application/json

{"filter":{"property":"Status","select":{"equals":"Done"}}}

Response: {"results":[{"id":"page_123","properties":{"Name":{"title":[{"text":{"content":"タスクA"}}]}}}]}
